import{_ as s,c as e,o as a,ae as t}from"./chunks/framework.BHrE6nLq.js";const g=JSON.parse('{"title":"Converting and Resizing Images in Libvirt/KVM and VirtualBox","description":"","frontmatter":{},"headers":[],"relativePath":"how_to/libvirt/managing-libvirt.md","filePath":"how_to/libvirt/managing-libvirt.md"}'),n={name:"how_to/libvirt/managing-libvirt.md"};function o(r,i,l,h,d,p){return a(),e("div",null,i[0]||(i[0]=[t('<h1 id="converting-and-resizing-images-in-libvirt-kvm-and-virtualbox" tabindex="-1">Converting and Resizing Images in Libvirt/KVM and VirtualBox <a class="header-anchor" href="#converting-and-resizing-images-in-libvirt-kvm-and-virtualbox" aria-label="Permalink to &quot;Converting and Resizing Images in Libvirt/KVM and VirtualBox&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Virtual machine (VM) disk images come in various formats depending on the virtualization platform, such as <code>.qcow2</code> for KVM, <code>.vdi</code> for VirtualBox, or <code>.img</code> (raw). This guide explains how to convert between these formats and resize them using tools like <code>qemu-img</code> on Linux or VirtualBox utilities on Windows. Whether you’re working with Libvirt/KVM or VirtualBox, these steps will help you manage your VM images effectively.</p><h2 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h2><ul><li><strong>Libvirt/KVM</strong>: A virtualization solution for Linux.</li><li><strong>Operating System</strong>: Linux (for KVM/Libvirt) or Windows (for VirtualBox).</li><li><strong>Image Formats</strong>: <code>.qcow2</code> (KVM), <code>.vdi</code> (VirtualBox), <code>.img</code> (raw), etc.</li><li><strong>VirtualBox</strong>: A cross-platform virtualization tool.</li></ul><h2 id="supported-qemu-img-format-strings" tabindex="-1">Supported <code>qemu-img</code> Format Strings <a class="header-anchor" href="#supported-qemu-img-format-strings" aria-label="Permalink to &quot;Supported `qemu-img` Format Strings&quot;">​</a></h2><p>The <code>qemu-img</code> tool supports multiple image formats. Use the corresponding argument when converting:</p><table tabindex="0"><thead><tr><th><strong>Image Format</strong></th><th><strong>Argument to <code>qemu-img</code></strong></th></tr></thead><tbody><tr><td>QCOW2 (KVM, Xen)</td><td><code>qcow2</code></td></tr><tr><td>QED (KVM)</td><td><code>qed</code></td></tr><tr><td>Raw</td><td><code>raw</code></td></tr><tr><td>VDI (VirtualBox)</td><td><code>vdi</code></td></tr><tr><td>VHD (Hyper-V)</td><td><code>vpc</code></td></tr><tr><td>VMDK (VMware)</td><td><code>vmdk</code></td></tr></tbody></table><h2 id="converting-images-on-linux-libvirt-kvm" tabindex="-1">Converting Images on Linux (Libvirt/KVM) <a class="header-anchor" href="#converting-images-on-linux-libvirt-kvm" aria-label="Permalink to &quot;Converting Images on Linux (Libvirt/KVM)&quot;">​</a></h2><p>This section assumes you’re using a Linux system. While the commands are similar for Libvirt on Windows, the environment setup may differ slightly.</p><h3 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li><p><strong>Prepare Your Environment</strong><br> Ensure <code>qemu-kvm</code> or <code>libvirt</code> is installed on your system. You’ll also need a sample VM image (e.g., <code>.qcow2</code>, <code>.vdi</code>) ready for conversion. Install <code>qemu-utils</code> if it’s not already present:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-utils</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For Debian/Ubuntu</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # For RHEL/CentOS/Rocky</span></span></code></pre></div></li><li><p><strong>Navigate to the Image Directory</strong><br> Move to the directory containing the image you want to convert. Replace <code>/path/to/image</code> with your actual path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/image</span></span></code></pre></div></li><li><p><strong>Convert the Image</strong><br> Use the <code>qemu-img convert</code> command to change the image format. The syntax is:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">source-forma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">destination-forma</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">source-imag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">output-imag</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><ul><li><code>-f</code>: Source format (e.g., <code>qcow2</code>).</li><li><code>-O</code>: Output format (e.g., <code>vdi</code>).</li><li><code>&lt;source-image&gt;</code>: Original image file.</li><li><code>&lt;output-image&gt;</code>: New image file after conversion.</li></ul><p><strong>Example</strong>: Convert a <code>.qcow2</code> image to <code>.vdi</code> (VirtualBox format):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vdi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CentOS-7-x86_64-GenericCloud.qcow2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> centos7.vdi</span></span></code></pre></div><p>Wait for the process to complete. Afterward, verify the new file exists:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lrth</span></span></code></pre></div><p>You should see both the original and converted images in the directory.</p></li></ol><h2 id="resizing-image-size-on-linux" tabindex="-1">Resizing Image Size on Linux <a class="header-anchor" href="#resizing-image-size-on-linux" aria-label="Permalink to &quot;Resizing Image Size on Linux&quot;">​</a></h2><p>Resizing a VM image adjusts its storage capacity. This is useful when you need more space or (less commonly) want to shrink an image.</p><h3 id="steps-1" tabindex="-1">Steps <a class="header-anchor" href="#steps-1" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li><p><strong>Navigate to the Image Directory</strong><br> Open a terminal on your Linux VM or host and change to the directory containing the image:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/image</span></span></code></pre></div></li><li><p><strong>Resize the Image</strong><br> Use the <code>qemu-img resize</code> command. The default size increase is additive, but shrinking requires the <code>--shrink</code> flag. Syntax:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resize</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">image-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">new-siz</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><strong>Example</strong>: Resize an image named <code>centos7</code> to 50GB:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> centos7</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 50G</span></span></code></pre></div><blockquote><p><strong>Note</strong>: Resizing typically only increases capacity. To reduce the size (e.g., smaller than the current capacity), use <code>--shrink</code>. Shrinking requires the image’s filesystem to be resized first to avoid data loss.</p></blockquote><p><strong>Example</strong>: Shrink an image to 20GB:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> centos7</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --shrink</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 20G</span></span></code></pre></div><p>Output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Image resized.</span></span></code></pre></div><p>Be cautious with shrinking, as it can corrupt data if the filesystem isn’t adjusted beforehand.</p></li></ol><h2 id="converting-vdi-to-raw-image-on-windows-with-virtualbox" tabindex="-1">Converting VDI to Raw Image on Windows with VirtualBox <a class="header-anchor" href="#converting-vdi-to-raw-image-on-windows-with-virtualbox" aria-label="Permalink to &quot;Converting VDI to Raw Image on Windows with VirtualBox&quot;">​</a></h2><p>For Windows users running VirtualBox, you can convert a <code>.vdi</code> image to a raw <code>.img</code> format using the <code>VBoxManage</code> tool.</p><h3 id="steps-2" tabindex="-1">Steps <a class="header-anchor" href="#steps-2" aria-label="Permalink to &quot;Steps&quot;">​</a></h3><ol><li><p><strong>Open Command Prompt and Navigate to VirtualBox Directory</strong><br> Open <code>cmd</code> (Command Prompt) and switch to the VirtualBox installation directory:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;C:\\Program Files\\Oracle\\VirtualBox&quot;</span></span></code></pre></div></li><li><p><strong>Run the Conversion Command</strong><br> Use <code>VBoxManage clonehd</code> to convert the <code>.vdi</code> file to raw format. Syntax:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VBoxManage clonehd </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;source-path&gt;.vdi&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;output-path&gt;.img&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">format raw</span></span></code></pre></div><p><strong>Example</strong>: Convert a VirtualBox image located in the user’s VMs folder:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VBoxManage clonehd </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;C:\\Users\\247\\VirtualBox VMs\\CentOS\\CentOS.vdi&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;C:\\Users\\247\\VirtualBox VMs\\CentOS\\centos7_convert.img&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">format raw</span></span></code></pre></div><p>Adjust the file paths to match your environment (e.g., replace <code>247</code> with your username and ensure the paths point to your <code>.vdi</code> file).</p></li><li><p><strong>Wait for Completion</strong><br> The process may take a few minutes depending on the image size. Once finished, check the output directory for the new <code>.img</code> file.</p></li></ol><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://docs.openstack.org/image-guide/convert-images.html" target="_blank" rel="noreferrer">OpenStack Image Guide: Convert Images</a></li><li><a href="https://askubuntu.com/questions/195139/how-to-convert-qcow2-virtual-disk-to-physical-machine-and-reversely" target="_blank" rel="noreferrer">AskUbuntu: Convert QCOW2 to Physical Machine</a></li><li><a href="https://gioacchinolonardo.medium.com/convert-vdi-virtualbox-to-raw-in-windows-c96bded29640" target="_blank" rel="noreferrer">Medium: Convert VDI to Raw in Windows</a></li></ul>',22)]))}const k=s(n,[["render",o]]);export{g as __pageData,k as default};
